using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Update with your actual namespace

public class ProductReviewController : Controller
{
    private readonly ApplicationDbContext _context;

    public ProductReviewController()
    {
        _context = new ApplicationDbContext();
    }

    public ActionResult Index(int productId)
    {
        var reviews = _context.Reviews.Where(r => r.ProductId == productId).ToList();
        var product = _context.Products.Find(productId);
        ViewBag.Product = product;

        return View(reviews);
    }

    [HttpPost]
    [ValidateAntiForgeryToken]
    public ActionResult SubmitReview(Review review)
    {
        if (ModelState.IsValid)
        {
            _context.Reviews.Add(review);
            _context.SaveChanges();
            return RedirectToAction("Index", new { productId = review.ProductId });
        }
        return View("Index");
    }
}

// Review Model
public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string UserName { get; set; }
    public string Content { get; set; }
}

// Razor view (Index.cshtml)
@model IEnumerable<YourNamespace.Models.Review>
@{
    ViewBag.Title = "Product Reviews";
    var product = ViewBag.Product as YourNamespace.Models.Product;
}

<h2>@product.Name Reviews</h2>

<form action="@Url.Action("SubmitReview", "ProductReview")" method="post">
    @Html.AntiForgeryToken()
    <input type="hidden" name="ProductId" value="@product.Id" />
    <div>
        <label for="UserName">Name:</label>
        <input type="text" name="UserName" required />
    </div>
    <div>
        <label for="Content">Review:</label>
        <textarea name="Content" required></textarea>
    </div>
    <button type="submit">Submit Review</button>
</form>

<h3>Reviews:</h3>
@foreach (var review in Model)
{
    <div>
        <strong>@review.UserName:</strong>
        <p>@Html.Raw(review.Content)</p>
    </div>
}